patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 53632efe913e..7974f4acb82b 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -14948,6 +14948,35 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {

       Value *Op = vectorizeOperand(E, 0, PostponedPHIs);

+      // If the operand type doesn't match the expected vector type, we need
+      // to insert a cast. This can happen when freeze is used on the result
+      // of a cast operation.
+      if (Op->getType() != VecTy) {
+        // Check if the original scalar operands were casts.
+        bool AllZExt = true;
+        bool AllSExt = true;
+        for (Value *V : E->Scalars) {
+          auto *FI = cast<FreezeInst>(V);
+          Value *Operand = FI->getOperand(0);
+          if (auto *CI = dyn_cast<CastInst>(Operand)) {
+            if (CI->getOpcode() == Instruction::ZExt)
+              AllSExt = false;
+            else if (CI->getOpcode() == Instruction::SExt)
+              AllZExt = false;
+            else
+              AllZExt = AllSExt = false;
+          } else {
+            AllZExt = AllSExt = false;
+          }
+        }
+        
+        if (AllZExt && !AllSExt) {
+          Op = Builder.CreateZExt(Op, VecTy);
+        } else if (AllSExt && !AllZExt) {
+          Op = Builder.CreateSExt(Op, VecTy);
+        }
+      }
+
       if (E->VectorizedValue) {
         LLVM_DEBUG(dbgs() << "SLP: Diamond merged for " << *VL0 << ".\n");
         return E->VectorizedValue;

