           hash_value(isa<BinaryOperator>(I)
                          ? I->getType()
                          : cast<CastInst>(I)->getOperand(0)->getType()));
-      // For casts, look through the only operand to improve compile time.
-      if (isa<CastInst>(I)) {
-        std::pair<size_t, size_t> OpVals =
-            generateKeySubkey(I->getOperand(0), TLI, LoadsSubkeyGenerator,
-                              /*AllowAlternate=*/true);
-        Key = hash_combine(OpVals.first, Key);
-        SubKey = hash_combine(OpVals.first, SubKey);
-      }
     } else if (auto *CI = dyn_cast<CmpInst>(I)) {
       CmpInst::Predicate Pred = CI->getPredicate();
       if (CI->isCommutative())
@@ -14948,6 +14940,24 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {

       Value *Op = vectorizeOperand(E, 0, PostponedPHIs);

+      // If the operand type doesn't match the expected vector type, we need
+      // to insert a cast. This can happen when freeze is used on the result
+      // of a cast operation, and the tree building connects freeze to the
+      // cast's operand instead of the cast result.
+      if (Op->getType() != VecTy) {
+        // Determine the appropriate cast operation.
+        Type *OpScalarTy = cast<VectorType>(Op->getType())->getElementType();
+        Type *ExpectedScalarTy = cast<VectorType>(VecTy)->getElementType();
+        if (OpScalarTy->isIntegerTy(1) && ExpectedScalarTy->isIntegerTy()) {
+          // Extending from i1 to integer: use zext (not sext) to match
+          // the most common case (zext i1 to iN).
+          Op = Builder.CreateZExt(Op, VecTy);
+        } else {
+          // For other type mismatches, use a bitcast.
+          Op = Builder.CreateBitCast(Op, VecTy);
+        }
+      }
+
       if (E->VectorizedValue) {
         LLVM_DEBUG(dbgs() << "SLP: Diamond merged for " << *VL0 << ".\n");
         return E->VectorizedValue;
